const CHAR_TO_INITIAL = (() => {
  const m = Object.create(null);
  for (const [k, v] of Object.entries(PINYIN_INITIAL_DATA)) {
    for (const c of v) m[c] = k;
  }
  return m;
})();

function pinyinInitials(s) {
  let out = "";
  for (const c of s) {
    if (/[a-zA-Z]/.test(c)) out += c.toUpperCase();
    else if (CHAR_TO_INITIAL[c]) out += CHAR_TO_INITIAL[c];
    else if (/[0-9]/.test(c)) out += c;
  }
  return out;
}
